const resp = $input.first().json;
const result = resp.results && resp.results[0] && resp.results[0].response && resp.results[0].response.result;
if (!result || !result.rows) { return []; }
const cols = result.cols.map(c => c.name);
const out = [];
for (const row of result.rows) {
  const L = {};
  row.forEach((cell, i) => { L[cols[i]] = (cell && cell.value !== undefined) ? cell.value : null; });
  const paid = !!L.gclid || (L.source || '').startsWith('lp-');
  const date = (L.createdAt || '').replace('T', ' ').slice(0, 16);
  out.push({ json: {
    'Lead ID': String(L.id || ''),
    Date: date,
    Name: L.name || '',
    Phone: L.phone || '',
    Email: L.email || '',
    City: L.city || '',
    State: L.state || '',
    Zip: L.zipCode || '',
    Project: L.projectType || '',
    Size: L.dumpsterSize || '',
    Source: paid ? 'Paid (Google Ads)' : 'Organic',
    Keyword: L.keyword || '',
    Status: L.status || 'new',
    'Job Value': L.jobValue || ''
  } });
}
return out;
